def gen(rng, size):
    n = rng.randint(1, max(1, min(size, 30)))
    adj = [set() for _ in range(n)]
    for i in range(1, n):
        j = rng.randrange(i)
        adj[i].add(j)
        adj[j].add(i)
    if n >= 2:
        for _ in range(rng.randint(0, n)):
            a, b = rng.sample(range(n), 2)
            adj[a].add(b)
            adj[b].add(a)
    return [[sorted(x + 1 for x in s) for s in adj]]

