class Solution:
    def cloneGraph(self, node):
        if node is None:
            return None
        memo = {}
        stack = [node]
        memo[id(node)] = Node(node.val)
        while stack:
            cur = stack.pop()
            copy = memo[id(cur)]
            for nb in cur.neighbors:
                if id(nb) not in memo:
                    memo[id(nb)] = Node(nb.val)
                    stack.append(nb)
                copy.neighbors.append(memo[id(nb)])
        return memo[id(node)]

