class Solution:
    def cloneGraph(self, node):
        if node is None:
            return None
        memo = {}
        def dfs(cur):
            if id(cur) in memo:
                return memo[id(cur)]
            copy = Node(cur.val)
            memo[id(cur)] = copy
            copy.neighbors = [dfs(nb) for nb in cur.neighbors]
            return copy
        return dfs(node)

