var cloneGraph = function(node) {
    if (!node) return null;
    const memo = new Map();
    const dfs = (cur) => {
        if (memo.has(cur)) return memo.get(cur);
        const copy = new Node(cur.val);
        memo.set(cur, copy);
        copy.neighbors = cur.neighbors.map(dfs);
        return copy;
    };
    return dfs(node);
};
